import org.apache.kafka.clients.producer.*;
import java.util.Properties;
import java.util.HashMap;

public class CustomKafkaProducer {
    public static void main(String[] args) {
        // create Kafka producer properties
        Properties props = new Properties();
        props.put("bootstrap.servers", "localhost:9092");
        props.put("key.serializer", "org.apache.kafka.common.serialization.StringSerializer");
        props.put("value.serializer", "org.apache.kafka.common.serialization.StringSerializer");

        // create Kafka producer
        Producer<String, String> producer = new KafkaProducer<>(props);

        // create custom headers
        HashMap<String, String> headers = new HashMap<>();
        headers.put("tracking-id", "12345");
        headers.put("user-id", "abcde");
        headers.put("custom-metadata", "custom value");

        // create Kafka producer record with custom headers
        ProducerRecord<String, String> record = new ProducerRecord<>("my-topic", "Hello World!", headers);

        // send Kafka producer record to Kafka topic
        producer.send(record);

        // flush and close Kafka producer
        producer.flush();
        producer.close();
    }
}